sql:
SELECT production_method 
FROM wines 
WHERE wine_id = 0;

SELECT wine_id, wine_type, quality_score 
FROM wines 
ORDER BY quality_score DESC;

SELECT *
FROM inspectors
WHERE inspector_name = 'Alice Johnson';

external_knowledge:
- "quite good" refers to an average overall sensory score above 7.5; 
- The evaluation year is specifically 2020; 
- The query also includes the locations of the vineyards where the grapes for the wines were harvested.

sql:
SELECT wine_id
FROM sensory_evaluation
WHERE overall_score < 5;

external_knowledge:
'specific vineyard' represents a particular vineyard of interest;
'detailed impressions' are the sensory evaluation scores (appearance, aroma, taste, finish, and overall);
'taste judges' refer to the evaluators who taste the wines;
'bouquet of sensory notes' is a metaphorical expression for the sensory evaluation scores;

sql:
SELECT * 
FROM wines 
WHERE wine_type = 'red';

SELECT vineyard_name
FROM vineyards
WHERE elevation > 800;

SELECT TYPEOF(alcohol) AS alcohol_type
FROM chemical_analysis
WHERE analysis_id = 1;

SELECT wine_id, quality_score
FROM wines
WHERE quality_score = (SELECT MAX(quality_score) FROM wines);

SELECT w.wine_type, b.batch_name 
FROM wines w 
JOIN batches b ON w.batch_id = b.batch_id;
